  ('Gelato', 'gelato', 'hybrid', 'A dessert-sweet California hybrid bred from Sunset Sherbet and Thin Mint GSC. Balanced, euphoric effects with a creamy, fruity flavor made it the backbone of the modern exotic scene.', array['Relaxed','Happy','Euphoric','Uplifted'], array['Sweet','Berry','Citrus'], array['Caryophyllene','Limonene','Humulene'], array['Sunset Sherbet','Thin Mint GSC'], 17, 25),
  ('Wedding Cake', 'wedding-cake', 'hybrid', 'An indica-leaning cross of Triangle Kush and Animal Mints with rich, tangy frosting flavors. Potent and relaxing without fully sedating, it became a menu staple nationwide.', array['Relaxed','Happy','Euphoric','Hungry'], array['Sweet','Vanilla','Earthy'], array['Limonene','Caryophyllene','Myrcene'], array['Triangle Kush','Animal Mints'], 20, 27),
